diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 00efd3c0eb72..5c8b52f3a3d8 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5504,15 +5504,31 @@ bool SimplifyCFGOpt::simplifyUnreachable(UnreachableInst *UI) {
   return Changed;
 }

-static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
+static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases,
+                               ConstantInt *&RangeStart) {
   assert(Cases.size() >= 1);

   array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
-  for (size_t I = 1, E = Cases.size(); I != E; ++I) {
-    if (Cases[I - 1]->getValue() != Cases[I]->getValue() + 1)
-      return false;
+
+  auto IsContiguousFrom = [&](const APInt &Start) {
+    APInt NumCases(Start.getBitWidth(), Cases.size());
+    for (ConstantInt *Case : Cases)
+      if ((Case->getValue() - Start).uge(NumCases))
+        return false;
+    return true;
+  };
+
+  if (IsContiguousFrom(Cases.back()->getValue())) {
+    RangeStart = Cases.back();
+    return true;
   }
-  return true;
+
+  if (IsContiguousFrom(Cases.front()->getValue())) {
+    RangeStart = Cases.front();
+    return true;
+  }
+
+  return false;
 }

 static void createUnreachableSwitchDefault(SwitchInst *Switch,
@@ -5584,14 +5600,19 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,

   // Figure out if one of the sets of cases form a contiguous range.
   SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
+  ConstantInt *RangeStart = nullptr;
   BasicBlock *ContiguousDest = nullptr;
   BasicBlock *OtherDest = nullptr;
-  if (!CasesA.empty() && casesAreContiguous(CasesA)) {
+  ConstantInt *CasesAStart = nullptr;
+  ConstantInt *CasesBStart = nullptr;
+  if (!CasesA.empty() && casesAreContiguous(CasesA, CasesAStart)) {
     ContiguousCases = &CasesA;
+    RangeStart = CasesAStart;
     ContiguousDest = DestA;
     OtherDest = DestB;
-  } else if (casesAreContiguous(CasesB)) {
+  } else if (casesAreContiguous(CasesB, CasesBStart)) {
     ContiguousCases = &CasesB;
+    RangeStart = CasesBStart;
     ContiguousDest = DestB;
     OtherDest = DestA;
   } else
@@ -5599,21 +5620,44 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,

   // Start building the compare and branch.

-  Constant *Offset = ConstantExpr::getNeg(ContiguousCases->back());
+  Constant *Offset = ConstantExpr::getNeg(RangeStart);
   Constant *NumCases =
       ConstantInt::get(Offset->getType(), ContiguousCases->size());

   Value *Sub = SI->getCondition();
   if (!Offset->isNullValue())
     Sub = Builder.CreateAdd(Sub, Offset, Sub->getName() + ".off");
-
+  Value *Cmp;
   Value *Cmp;
   // If NumCases overflowed, then all possible values jump to the successor.
   if (NumCases->isNullValue() && !ContiguousCases->empty())
     Cmp = ConstantInt::getTrue(SI->getContext());
   else
     Cmp = Builder.CreateICmpULT(Sub, NumCases, "switch");
-  BranchInst *NewBI = Builder.CreateCondBr(Cmp, ContiguousDest, OtherDest);
+
+  BasicBlock *TrueDest = ContiguousDest;
+  BasicBlock *FalseDest = OtherDest;
+  if (auto *II = dyn_cast<IntrinsicInst>(SI->getCondition())) {
+    Intrinsic::ID IID = II->getIntrinsicID();
+    if ((IID == Intrinsic::ucmp || IID == Intrinsic::scmp) &&
+        ContiguousCases->size() == 2) {
+      bool HasNegOne = false, HasZero = false;
+      for (ConstantInt *Case : *ContiguousCases) {
+        HasNegOne |= Case->isMinusOne();
+        HasZero |= Case->isZero();
+      }
+      if (HasNegOne && HasZero) {
+        ICmpInst::Predicate Pred =
+            IID == Intrinsic::ucmp ? ICmpInst::ICMP_UGT : ICmpInst::ICMP_SGT;
+        Cmp = Builder.CreateICmp(Pred, II->getArgOperand(0),
+                                 II->getArgOperand(1), "cmp");
+        TrueDest = OtherDest;
+        FalseDest = ContiguousDest;
+      }
+    }
+  }
+
+  BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);

   // Update weight for the newly-created conditional branch.
   if (hasBranchWeightMD(*SI)) {
@@ -7156,7 +7200,12 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
-  if (Options.ConvertSwitchRangeToICmp && turnSwitchRangeIntoICmp(SI, Builder))
+  bool CondIsCmpIntrinsic = false;
+  if (auto *II = dyn_cast<IntrinsicInst>(SI->getCondition()))
+    CondIsCmpIntrinsic = II->getIntrinsicID() == Intrinsic::ucmp ||
+                         II->getIntrinsicID() == Intrinsic::scmp;
+  if ((Options.ConvertSwitchRangeToICmp || CondIsCmpIntrinsic) &&
+      turnSwitchRangeIntoICmp(SI, Builder))
     return requestResimplify();

   // Remove unreachable cases.

