static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases,
                               ConstantInt *&RangeStart) {
  assert(Cases.size() >= 1);

  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);

  auto IsContiguousFrom = [&](const APInt &Start) {
    APInt NumCases(Start.getBitWidth(), Cases.size());
    for (ConstantInt *Case : Cases)
      if ((Case->getValue() - Start).uge(NumCases))
        return false;
    return true;
  };

  if (IsContiguousFrom(Cases.back()->getValue())) {
    RangeStart = Cases.back();
    return true;
  }

  if (IsContiguousFrom(Cases.front()->getValue())) {
    RangeStart = Cases.front();
    return true;
  }

  return false;
}
